# Fibonacci Number Using Recursion in C++

## Overview
This program demonstrates computing the nth Fibonacci number using recursion, with multiple implementations ranging from basic to optimized approaches.

## Implementation

```cpp
#include <iostream>
#include <unordered_map>
#include <stdexcept>
#include <chrono>

// ============================================================
// 1. Basic Recursive Implementation
// ============================================================
long long fibBasic(int n) {
    if (n < 0) {
        throw std::invalid_argument("n must be a non-negative integer");
    }
    if (n == 0) return 0;
    if (n == 1) return 1;

    return fibBasic(n - 1) + fibBasic(n - 2);
}

// ============================================================
// 2. Memoized Recursive Implementation (Top-Down DP)
// ============================================================
long long fibMemo(int n, std::unordered_map<int, long long>& memo) {
    if (n < 0) {
        throw std::invalid_argument("n must be a non-negative integer");
    }
    if (n == 0) return 0;
    if (n == 1) return 1;

    // Return cached result if available
    auto it = memo.find(n);
    if (it != memo.end()) {
        return it->second;
    }

    // Compute and cache the result
    memo[n] = fibMemo(n - 1, memo) + fibMemo(n - 2, memo);
    return memo[n];
}

// Wrapper function for cleaner interface
long long fibMemoized(int n) {
    std::unordered_map<int, long long> memo;
    return fibMemo(n, memo);
}

// ============================================================
// 3. Tail-Recursive Implementation
// ============================================================
long long fibTailHelper(int n, long long prev, long long curr) {
    if (n == 0) return prev;
    if (n == 1) return curr;
    return fibTailHelper(n - 1, curr, prev + curr);
}

long long fibTail(int n) {
    if (n < 0) {
        throw std::invalid_argument("n must be a non-negative integer");
    }
    return fibTailHelper(n, 0, 1);
}

// ============================================================
// Utility: Benchmark a function
// ============================================================
template <typename Func>
void benchmark(const std::string& name, Func func, int n) {
    auto start = std::chrono::high_resolution_clock::now();
    long long result = func(n);
    auto end = std::chrono::high_resolution_clock::now();

    auto duration = std::chrono::duration_cast<std::chrono::microseconds>(end - start);
    std::cout << name << "(fib(" << n << ") = " << result
              << ") took: " << duration.count() << " µs\n";
}

// ============================================================
// Main Program
// ============================================================
int main() {
    // --- Display Fibonacci Sequence ---
    std::cout << "========================================\n";
    std::cout << "       Fibonacci Sequence (0-10)        \n";
    std::cout << "========================================\n";

    std::cout << "Index: ";
    for (int i = 0; i <= 10; ++i) std::cout << i << "\t";
    std::cout << "\nValue: ";
    for (int i = 0; i <= 10; ++i) std::cout << fibTail(i) << "\t";
    std::cout << "\n\n";

    // --- Compare All Implementations ---
    std::cout << "========================================\n";
    std::cout << "  Comparing Implementations (n = 10)   \n";
    std::cout << "========================================\n";

    int n = 10;
    std::cout << "Basic Recursive   : fib(" << n << ") = " << fibBasic(n)     << "\n";
    std::cout << "Memoized Recursive: fib(" << n << ") = " << fibMemoized(n)  << "\n";
    std::cout << "Tail Recursive    : fib(" << n << ") = " << fibTail(n)      << "\n\n";

    // --- Performance Benchmark ---
    std::cout << "========================================\n";
    std::cout << "         Performance Benchmark          \n";
    std::cout << "========================================\n";

    benchmark("Basic    ", fibBasic,    35);
    benchmark("Memoized ", fibMemoized, 35);
    benchmark("Tail     ", fibTail,     35);
    std::cout << "\n";

    // --- Large Numbers with Memoized ---
    std::cout << "========================================\n";
    std::cout << "       Large Fibonacci Numbers          \n";
    std::cout << "========================================\n";

    for (int i : {40, 50, 60, 70, 80, 90}) {
        std::cout << "fib(" << i << ") = " << fibMemoized(i) << "\n";
